# ---------------------------------------------------------------------------
# Apply
# ---------------------------------------------------------------------------

def apply(locale, patches, new_items):
    path = MSG / locale / "sss.json"
    with path.open("r", encoding="utf-8") as f:
        d = json.load(f)
    cats = d["sss"]["categories"]
    for (ci, ii, nq, na) in patches:
        if nq is not None:
            cats[ci]["items"][ii]["question"] = nq
        cats[ci]["items"][ii]["answer"] = na
    for (ci, new) in new_items:
        cats[ci]["items"].append(new)
    with path.open("w", encoding="utf-8") as f:
        json.dump(d, f, ensure_ascii=False, indent=2)
    total = sum(len(c["items"]) for c in cats)
    print(f"{locale}: patched {len(patches)}, appended {len(new_items)} → {total} Q&A")

apply("en", EN_PATCHES, EN_NEW)
apply("de", DE_PATCHES, DE_NEW)
apply("ru", RU_PATCHES, RU_NEW)
apply("fa", FA_PATCHES, FA_NEW)
